export const PATH_SHOP = '/';
export const PATH_CATEGORIES = '/categories';
export const PATH_CONTACT = '/contact';
export const PATH_RECIPES = '/recipes';
export const PATH_ORDERS = '/orders';
export const PATH_STATISTICS = '/statistics';
export const PATH_ABOUT = '/about';
export const PATH_LOGIN = '/login';
export const PATH_LOGOUT = '/logout';
export const PATH_REGISTRATION = '/registration';
export const PATH_BASKET = '/basket';
export const PATH_SEARCH = '/search';
export const PATH_CUSTOMIZATIONS = '/customizations';
export const PATH_ACCOUNT = '/account';


export const LINKS_NAV = [
    { path: PATH_SHOP, label: 'home' },
    { path: PATH_CATEGORIES, label: 'Categories' },
    { path: PATH_RECIPES, label: 'Recipes' },
    { path: PATH_ORDERS, label: 'Orders' },
    { path: PATH_STATISTICS, label: 'Statistics' },
    { path: PATH_ABOUT, label: 'About' },
    { path: PATH_CONTACT, label: 'Contact' }
]

export const LINKS_AUTH = [
    { path: PATH_SEARCH, image: 'https://www.flaticon.com/premium-icon/icons/svg/2997/2997940.svg' },
    { path: PATH_LOGIN, label: 'Sign in' },
    { path: PATH_REGISTRATION, label: 'Registration' },
    { path: PATH_BASKET, image: 'https://image.flaticon.com/icons/png/512/626/626443.png' },
    { path: PATH_CUSTOMIZATIONS, label: 'Customizations' }
]
